INSERT INTO "05_grc_library"."22_dtl_requirement_properties"
  (id, requirement_id, property_key, property_value, created_at, updated_at)
VALUES
  ('285a3335-0f91-4fee-9a1a-d733ffcb1ebb', '77a6258f-38c8-4825-b12d-4b9e1cd48771', 'name', 'Consent and Notice Management', '2026-04-02 06:48:55.589178', '2026-04-02 06:48:55.589178'),
  ('06ecaf72-4a91-4ffb-86b3-7d851c16a9be', '77a6258f-38c8-4825-b12d-4b9e1cd48771', 'description', 'Ensure personal data is processed based on valid, transparent, and lawful consent from data principals.', '2026-04-02 06:48:55.589178', '2026-04-02 06:48:55.589178'),
  ('e4a4c5b6-9870-4055-8437-8befb164566e', 'bfae0077-81a3-4d87-99ca-f8cb88f9c83c', 'name', 'Data Principal Rights', '2026-04-02 06:48:55.631315', '2026-04-02 06:48:55.631315'),
  ('38fbd4aa-7a33-4538-b8d0-296a58ede31d', 'bfae0077-81a3-4d87-99ca-f8cb88f9c83c', 'description', 'Ensure mechanisms exist to support and fulfill the rights of data principals regarding their personal data.', '2026-04-02 06:48:55.631315', '2026-04-02 06:48:55.631315'),
  ('8c372dcb-aeb7-4a18-b22b-a7833fd257b5', '86e6e16c-70ec-42db-809e-b1c607678a97', 'name', 'Data Security Safeguards', '2026-04-02 06:48:55.662743', '2026-04-02 06:48:55.662743'),
  ('43e0caf4-41e5-4c4b-948e-669449802e84', '86e6e16c-70ec-42db-809e-b1c607678a97', 'description', 'Implement technical and organizational safeguards to protect personal data from unauthorized access and loss.', '2026-04-02 06:48:55.662743', '2026-04-02 06:48:55.662743'),
  ('45d1fc7a-02ae-4fe7-bbc0-21c7e75b10df', 'eaf92fe0-46fa-4070-9c3c-f9a290bd9e5a', 'name', 'Breach and Incident Management', '2026-04-02 06:48:55.695239', '2026-04-02 06:48:55.695239'),
  ('9dcec299-7e67-45cd-9d32-86912f67216b', 'eaf92fe0-46fa-4070-9c3c-f9a290bd9e5a', 'description', 'Establish processes to detect, respond to, and report personal data breaches promptly.', '2026-04-02 06:48:55.695239', '2026-04-02 06:48:55.695239'),
  ('9ac51af6-0b69-40a8-8448-372cab9e7f0a', '23849615-e3c3-43e2-a442-c6d80c227049', 'name', 'Third Party and Cross Border Data Processing', '2026-04-02 06:48:55.726297', '2026-04-02 06:48:55.726297'),
  ('f82095f7-8f47-4979-beaf-9f03e6342fa5', '23849615-e3c3-43e2-a442-c6d80c227049', 'description', 'Ensure personal data shared with processors and across jurisdictions remains protected and lawful.', '2026-04-02 06:48:55.726297', '2026-04-02 06:48:55.726297'),
  ('24fe2b7b-ce3c-4ac7-aef3-574d827090c5', 'badc9417-8e2f-4930-a775-cd5106ec1053', 'name', 'Data Protection Governance', '2026-04-02 06:48:55.761007', '2026-04-02 06:48:55.761007'),
  ('b8c02709-8508-4b4e-bf16-44d3943d7c31', 'badc9417-8e2f-4930-a775-cd5106ec1053', 'description', 'Establish governance structures, accountability, and oversight for personal data protection.', '2026-04-02 06:48:55.761007', '2026-04-02 06:48:55.761007'),
  ('ad05ae33-9448-4cce-9603-0919d6399ccc', '8a4d1820-c312-42b1-beaa-eea8aed66b88', 'name', 'Transparent Privacy Notices', '2026-04-02 06:48:55.789758', '2026-04-02 06:48:55.789758'),
  ('430c7b7f-caf1-40d3-a8de-3e8ef3cca328', '8a4d1820-c312-42b1-beaa-eea8aed66b88', 'description', 'Organizations must provide clear notice describing how personal data is collected and used.', '2026-04-02 06:48:55.789758', '2026-04-02 06:48:55.789758'),
  ('f4c09d69-ee15-4754-b301-6a3a3af0f1ec', '3efe8709-053f-4702-a461-abec7d0128b3', 'name', 'Consent Collection and Validation', '2026-04-02 06:48:55.816598', '2026-04-02 06:48:55.816598'),
  ('27c8f9d4-3c74-4874-a3ac-fbd4070ffbbe', '3efe8709-053f-4702-a461-abec7d0128b3', 'description', 'Consent must be explicit, verifiable, and obtained prior to processing personal data.', '2026-04-02 06:48:55.816598', '2026-04-02 06:48:55.816598'),
  ('74cb8767-1757-44b3-826f-c7c3e50c017b', '1eab279c-0ba3-43d6-b63a-1b6aac4e0d9c', 'name', 'Consent Withdrawal Management', '2026-04-02 06:48:55.845036', '2026-04-02 06:48:55.845036'),
  ('78f2a2b8-4479-409b-831a-f3ee47bb5be2', '1eab279c-0ba3-43d6-b63a-1b6aac4e0d9c', 'description', 'Data principals must be able to withdraw consent easily and have processing halted accordingly.', '2026-04-02 06:48:55.845036', '2026-04-02 06:48:55.845036'),
  ('e7ad316c-7a1c-4ff9-9577-b97ad0b7d1dc', 'a743ca40-13d5-4d19-a7a8-1d868ccc9d59', 'name', 'Access and Correction Rights', '2026-04-02 06:48:55.871892', '2026-04-02 06:48:55.871892'),
  ('44d0aca2-f3bb-4fc4-b879-dcd07090a450', 'a743ca40-13d5-4d19-a7a8-1d868ccc9d59', 'description', 'Data principals must be able to access and correct personal data maintained by the organization.', '2026-04-02 06:48:55.871892', '2026-04-02 06:48:55.871892'),
  ('575b88a8-c3fa-458c-9444-798894985dc9', 'b214ac95-3d4a-43a6-9dc7-ba8c4242abfe', 'name', 'Data Erasure Requests', '2026-04-02 06:48:55.896987', '2026-04-02 06:48:55.896987'),
  ('069887bb-0cd6-42fa-a668-8dd52c9483ce', 'b214ac95-3d4a-43a6-9dc7-ba8c4242abfe', 'description', 'Organizations must provide mechanisms to delete personal data when legally required or requested.', '2026-04-02 06:48:55.896987', '2026-04-02 06:48:55.896987'),
  ('0368ad9d-0b62-4b15-bb0d-4a3e136d9435', '5a7a4773-3227-4c89-b9c0-d7ba20dc0c79', 'name', 'Grievance Redressal Process', '2026-04-02 06:48:55.922954', '2026-04-02 06:48:55.922954'),
  ('b2a9d1e0-5541-43ad-9b75-6133ae679189', '5a7a4773-3227-4c89-b9c0-d7ba20dc0c79', 'description', 'A structured grievance process must exist to resolve complaints from data principals.', '2026-04-02 06:48:55.922954', '2026-04-02 06:48:55.922954'),
  ('2db22b3f-1a9b-4790-8a07-29825ce663bc', '4605fc8f-8192-4dae-8951-fa57978ca56c', 'name', 'Access Control for Personal Data', '2026-04-02 06:48:55.947229', '2026-04-02 06:48:55.947229'),
  ('2be59957-96ea-48d0-8bfe-f76d240c1c06', '4605fc8f-8192-4dae-8951-fa57978ca56c', 'description', 'Access to personal data must be restricted based on roles and business need.', '2026-04-02 06:48:55.947229', '2026-04-02 06:48:55.947229'),
  ('a4132804-7cf1-4080-b29a-e3e819d875ef', 'b185fd6a-0424-433e-9432-d9825d3ffb2d', 'name', 'Data Protection and Encryption', '2026-04-02 06:48:55.971318', '2026-04-02 06:48:55.971318'),
  ('4f0c3f9c-d487-407e-bedf-784dd4ef8470', 'b185fd6a-0424-433e-9432-d9825d3ffb2d', 'description', 'Personal data must be protected using encryption and secure storage practices.', '2026-04-02 06:48:55.971318', '2026-04-02 06:48:55.971318'),
  ('d8a90365-59bd-4890-81e5-39f010d7f4ce', '8ec07dfc-df98-4e54-b16a-ea0d2dce5dbc', 'name', 'Secure Processing and Storage', '2026-04-02 06:48:55.997662', '2026-04-02 06:48:55.997662'),
  ('0cc5f156-9629-49b0-bd32-f2aa10ddb52b', '8ec07dfc-df98-4e54-b16a-ea0d2dce5dbc', 'description', 'Systems processing personal data must enforce secure configuration and vulnerability management.', '2026-04-02 06:48:55.997662', '2026-04-02 06:48:55.997662'),
  ('922a0396-df4d-4a33-b005-19656524045f', 'f756a203-0020-4664-914d-37022f1809e1', 'name', 'Incident Detection and Monitoring', '2026-04-02 06:48:56.021768', '2026-04-02 06:48:56.021768'),
  ('23f6df34-ac80-4002-936b-002edab8b112', 'f756a203-0020-4664-914d-37022f1809e1', 'description', 'Organizations must monitor systems to detect suspicious activity involving personal data.', '2026-04-02 06:48:56.021768', '2026-04-02 06:48:56.021768'),
  ('0912f58a-b571-4b21-aa80-27f27bad1b2f', 'ca5d7bad-1ce1-4f89-8683-8538d8ffb965', 'name', 'Breach Response Procedures', '2026-04-02 06:48:56.045582', '2026-04-02 06:48:56.045582'),
  ('d481b4db-1866-4a22-a471-fb95e40cce94', 'ca5d7bad-1ce1-4f89-8683-8538d8ffb965', 'description', 'A formal incident response plan must exist for personal data breach scenarios.', '2026-04-02 06:48:56.045582', '2026-04-02 06:48:56.045582'),
  ('369f2294-e629-4d71-820d-d77c510d8dcc', 'ec06de60-692a-4c32-b5f1-d54f6e8ccbb0', 'name', 'Regulatory Breach Notification', '2026-04-02 06:48:56.070287', '2026-04-02 06:48:56.070287'),
  ('71adf1ee-d25a-40bf-bf25-f880b2178316', 'ec06de60-692a-4c32-b5f1-d54f6e8ccbb0', 'description', 'Personal data breaches must be reported to relevant authorities and impacted individuals where required.', '2026-04-02 06:48:56.070287', '2026-04-02 06:48:56.070287'),
  ('23411a0e-5099-4e01-83d9-2d49b9c1b2f6', '74203051-2264-4de1-9218-7d70f708bbfc', 'name', 'Third Party Processor Governance', '2026-04-02 06:48:56.096586', '2026-04-02 06:48:56.096586'),
  ('3edb7a15-8c5c-4418-95b8-354c2c64cf17', '74203051-2264-4de1-9218-7d70f708bbfc', 'description', 'Organizations must evaluate and manage the compliance posture of third party processors.', '2026-04-02 06:48:56.096586', '2026-04-02 06:48:56.096586'),
  ('779eedf4-878b-4d4d-acdf-f0c05d643ea3', 'aca4f0d1-cdd5-42c6-87a9-de9d00cc8a4c', 'name', 'Cross Border Data Transfer Controls', '2026-04-02 06:48:56.12277', '2026-04-02 06:48:56.12277'),
  ('d90bf829-f7e8-4f58-a0ba-4fbdd34aa9c0', 'aca4f0d1-cdd5-42c6-87a9-de9d00cc8a4c', 'description', 'Transfers of personal data outside the jurisdiction must comply with legal restrictions.', '2026-04-02 06:48:56.12277', '2026-04-02 06:48:56.12277'),
  ('c32a4b09-d3a7-4863-9748-c50533449344', '3ad741a4-4131-46ab-a94f-5008da2d6d5a', 'name', 'Processor Contractual Safeguards', '2026-04-02 06:48:56.151869', '2026-04-02 06:48:56.151869'),
  ('aa0feb96-37bf-4825-bce2-f4444677e6fe', '3ad741a4-4131-46ab-a94f-5008da2d6d5a', 'description', 'Contracts with processors must include obligations for data protection and breach reporting.', '2026-04-02 06:48:56.151869', '2026-04-02 06:48:56.151869'),
  ('333d16f4-0891-49dd-8311-4fe52b957f1c', 'd55fc58e-459e-4c34-a702-86d94ad22e97', 'name', 'Data Protection Policies', '2026-04-02 06:48:56.180448', '2026-04-02 06:48:56.180448'),
  ('79e30284-5e22-4421-9d57-d83ff7923148', 'd55fc58e-459e-4c34-a702-86d94ad22e97', 'description', 'Organizations must maintain documented policies governing personal data handling.', '2026-04-02 06:48:56.180448', '2026-04-02 06:48:56.180448'),
  ('0e1bba89-cfe9-4c1f-870c-90f65490776d', 'f8a1b3ff-3bc3-46f7-8ea9-009c64300048', 'name', 'Data Inventory and Classification', '2026-04-02 06:48:56.206746', '2026-04-02 06:48:56.206746'),
  ('dc807f6f-c6e1-487d-bc99-c6f42136735c', 'f8a1b3ff-3bc3-46f7-8ea9-009c64300048', 'description', 'Personal data assets must be inventoried and classified to enable effective protection.', '2026-04-02 06:48:56.206746', '2026-04-02 06:48:56.206746'),
  ('f59262c3-6957-422c-81ae-ac9ed8fb1043', '70c6a365-7e92-4155-8363-ecec509f45cd', 'name', 'Training and Awareness', '2026-04-02 06:48:56.233216', '2026-04-02 06:48:56.233216'),
  ('4db9cf0e-afd6-46bc-8e9e-c2bbc5b267d3', '70c6a365-7e92-4155-8363-ecec509f45cd', 'description', 'Employees must receive training on personal data protection obligations and practices.', '2026-04-02 06:48:56.233216', '2026-04-02 06:48:56.233216')
INSERT INTO "05_grc_library"."13_fct_controls"
  (id, framework_id, requirement_id, tenant_key, control_code,
INSERT INTO "05_grc_library"."23_dtl_control_properties"
  (id, control_id, property_key, property_value, created_at, updated_at)
VALUES
  ('2c181a8c-43b0-4f62-b545-8b416ca63288', '2a55dcac-29b7-42fb-9c0b-2d1acec67db4', 'name', 'Publish Clear Privacy Notices', '2026-04-02 06:48:56.259815', '2026-04-02 06:48:56.259815'),
  ('01f0cd70-3342-4244-ac49-0debf2169c42', '2a55dcac-29b7-42fb-9c0b-2d1acec67db4', 'description', 'Publish privacy notices describing the categories of personal data collected and purposes of processing. Transparency ensures individuals understand how their data is used.', '2026-04-02 06:48:56.259815', '2026-04-02 06:48:56.259815'),
  ('05909b36-5fec-47f3-82f1-6aae470ea3dd', '2a55dcac-29b7-42fb-9c0b-2d1acec67db4', 'guidance', 'Provide notices on websites, apps, and data collection interfaces.', '2026-04-02 06:48:56.259815', '2026-04-02 06:48:56.259815'),
  ('ab118b03-8c1d-4cb4-98a5-56ff168a2ea0', '2a55dcac-29b7-42fb-9c0b-2d1acec67db4', 'implementation_guidance', '["Document categories of personal data collected", "Describe purpose of data processing", "Display notice at collection points", "Review notices annually"]', '2026-04-02 06:48:56.259815', '2026-04-02 06:48:56.259815'),
  ('8a9c18d1-9ff0-49ad-a2fe-9161f6569f87', '23a06dc5-5d43-46c1-b3c8-25f221c0a3ee', 'name', 'Maintain Versioned Privacy Notice Records', '2026-04-02 06:48:56.296266', '2026-04-02 06:48:56.296266'),
  ('2a3eb56b-fa65-4bce-949b-29ca0c262222', '23a06dc5-5d43-46c1-b3c8-25f221c0a3ee', 'description', 'Maintain historical records of privacy notices issued to users. This ensures legal traceability and accountability.', '2026-04-02 06:48:56.296266', '2026-04-02 06:48:56.296266'),
  ('5782ee8e-96d5-466f-a923-e2bd3e040c65', '23a06dc5-5d43-46c1-b3c8-25f221c0a3ee', 'guidance', 'Store notice versions and timestamps in document management systems.', '2026-04-02 06:48:56.296266', '2026-04-02 06:48:56.296266'),
  ('161b334b-df30-48e4-ac1c-711d607871de', '23a06dc5-5d43-46c1-b3c8-25f221c0a3ee', 'implementation_guidance', '["Maintain notice version history", "Record publication dates", "Archive previous notices", "Track updates and approvals"]', '2026-04-02 06:48:56.296266', '2026-04-02 06:48:56.296266'),
  ('f1e007d2-f0f4-4d5c-ac37-1164a35a62e8', 'd94c10ab-adfb-43b8-9e31-3317b68ec238', 'name', 'Collect Explicit User Consent', '2026-04-02 06:48:56.322793', '2026-04-02 06:48:56.322793'),
  ('c568174c-7503-4c27-acfa-1435202cb27d', 'd94c10ab-adfb-43b8-9e31-3317b68ec238', 'description', 'Ensure explicit consent is obtained prior to processing personal data. Consent must be freely given and verifiable.', '2026-04-02 06:48:56.322793', '2026-04-02 06:48:56.322793'),
  ('860d3feb-d6e3-40ad-8235-68e9745c7ae8', 'd94c10ab-adfb-43b8-9e31-3317b68ec238', 'guidance', 'Use consent prompts or checkboxes that require affirmative action.', '2026-04-02 06:48:56.322793', '2026-04-02 06:48:56.322793'),
  ('18bbc9f1-acfe-4c74-82cd-cc617c78e976', 'd94c10ab-adfb-43b8-9e31-3317b68ec238', 'implementation_guidance', '["Implement consent forms", "Capture timestamp of consent", "Link consent to user identity", "Store consent records"]', '2026-04-02 06:48:56.322793', '2026-04-02 06:48:56.322793'),
  ('d2892606-351f-4688-9aef-9aa5169e2d34', 'f3919571-100e-4f52-adef-01ca9777ec2e', 'name', 'Validate Consent Prior to Data Processing', '2026-04-02 06:48:56.350053', '2026-04-02 06:48:56.350053'),
  ('a25d5554-e2a0-4938-9205-821e145d06bd', 'f3919571-100e-4f52-adef-01ca9777ec2e', 'description', 'Verify consent status before collecting or processing personal data. This prevents unauthorized processing.', '2026-04-02 06:48:56.350053', '2026-04-02 06:48:56.350053'),
  ('4b3f1d56-5531-4e0a-a0f2-129cf8e46428', 'f3919571-100e-4f52-adef-01ca9777ec2e', 'guidance', 'Integrate consent checks within application workflows.', '2026-04-02 06:48:56.350053', '2026-04-02 06:48:56.350053'),
  ('73a55856-f588-4fa3-80bf-386b8976b0de', 'f3919571-100e-4f52-adef-01ca9777ec2e', 'implementation_guidance', '["Add consent verification logic", "Block processing without consent", "Maintain consent validation logs", "Periodically audit consent records"]', '2026-04-02 06:48:56.350053', '2026-04-02 06:48:56.350053'),
  ('f8e53440-76b4-45ea-8d37-e9046eda01c7', '2e3d58ad-3216-43f3-ae80-6c3880840089', 'name', 'Provide Consent Withdrawal Mechanisms', '2026-04-02 06:48:56.402739', '2026-04-02 06:48:56.402739'),
  ('7894262c-0dc2-4da5-b01f-b46f56f4214b', '2e3d58ad-3216-43f3-ae80-6c3880840089', 'description', 'Enable individuals to withdraw previously granted consent easily. Withdrawal must stop further processing.', '2026-04-02 06:48:56.402739', '2026-04-02 06:48:56.402739'),
  ('72179f3c-162d-4665-9b40-5ee52f66df64', '2e3d58ad-3216-43f3-ae80-6c3880840089', 'guidance', 'Offer withdrawal options in account settings or service portals.', '2026-04-02 06:48:56.402739', '2026-04-02 06:48:56.402739'),
  ('3a3b2434-ba9d-4d85-acf4-da470df45730', '2e3d58ad-3216-43f3-ae80-6c3880840089', 'implementation_guidance', '["Provide user withdrawal interface", "Record withdrawal requests", "Update consent records immediately", "Notify systems to halt processing"]', '2026-04-02 06:48:56.402739', '2026-04-02 06:48:56.402739'),
  ('51f8d6a1-455b-4168-ad4a-b47678132f5c', '5ad49965-4ff7-4f92-9f5c-c1278104a25a', 'name', 'Audit Consent Withdrawal Processing', '2026-04-02 06:48:56.428023', '2026-04-02 06:48:56.428023'),
