  ('d5326bd2-6767-4705-8cb2-52db85886f16', 'c93f2e54-d760-4ebb-9a3d-17b01574035f', 'description', 'Evaluate third party processors for compliance with data protection requirements. This reduces risk from external partners.', '2026-04-02 06:48:56.902808', '2026-04-02 06:48:56.902808'),
  ('e6b93afd-bfca-41b5-8a19-29c156edc56b', 'c93f2e54-d760-4ebb-9a3d-17b01574035f', 'guidance', 'Perform due diligence and security assessments.', '2026-04-02 06:48:56.902808', '2026-04-02 06:48:56.902808'),
