  ('614a55b4-123d-4ec0-a5da-c92e07c77486', '65f9561c-4b23-4034-94ce-845aa8adeab9', 'name', 'Monitor Processor Compliance', '2026-04-02 06:48:56.925323', '2026-04-02 06:48:56.925323'),
  ('db7a375c-5bf7-4445-a247-5477f83d4371', '65f9561c-4b23-4034-94ce-845aa8adeab9', 'description', 'Continuously monitor third party processors for compliance with contractual and regulatory requirements. Ongoing monitoring reduces operational risk.', '2026-04-02 06:48:56.925323', '2026-04-02 06:48:56.925323'),
  ('d1a6c094-f269-429d-8b6a-c0050ef50d6d', '65f9561c-4b23-4034-94ce-845aa8adeab9', 'guidance', 'Conduct periodic vendor reviews.', '2026-04-02 06:48:56.925323', '2026-04-02 06:48:56.925323'),
  ('ebe350ec-53d6-48aa-a5fc-326f1f894bfc', '65f9561c-4b23-4034-94ce-845aa8adeab9', 'implementation_guidance', '["Track vendor compliance status", "Review audit reports", "Monitor incidents involving vendors", "Maintain vendor risk register"]', '2026-04-02 06:48:56.925323', '2026-04-02 06:48:56.925323'),
  ('8604dbe2-47bd-4c2b-b67c-9fed654ebcd1', '6696e699-a11d-419c-b9e6-1ec71d6dc1da', 'name', 'Review Cross Border Data Transfers', '2026-04-02 06:48:56.947366', '2026-04-02 06:48:56.947366'),
  ('96dcd55e-0107-42f6-8cfa-e12738742d49', '6696e699-a11d-419c-b9e6-1ec71d6dc1da', 'description', 'Ensure cross border transfers of personal data comply with regulatory requirements. Improper transfers can lead to legal violations.', '2026-04-02 06:48:56.947366', '2026-04-02 06:48:56.947366'),
  ('d90cce1d-e44e-4cfd-9082-8ed08ba2187d', '6696e699-a11d-419c-b9e6-1ec71d6dc1da', 'guidance', 'Document jurisdictions and transfer mechanisms.', '2026-04-02 06:48:56.947366', '2026-04-02 06:48:56.947366'),
  ('f0a33d62-7e99-4954-98b4-46e06497b013', '6696e699-a11d-419c-b9e6-1ec71d6dc1da', 'implementation_guidance', '["Identify transfer destinations", "Review legal restrictions", "Document lawful transfer mechanisms", "Maintain transfer records"]', '2026-04-02 06:48:56.947366', '2026-04-02 06:48:56.947366'),
  ('20e626a2-432e-48ff-83f3-fc45b22425ef', '27e8116c-7cbd-4cea-a520-4a1f4e442768', 'name', 'Approve International Data Transfers', '2026-04-02 06:48:56.971729', '2026-04-02 06:48:56.971729'),
  ('74c8f835-6f5f-4bae-914c-9912a689c175', '27e8116c-7cbd-4cea-a520-4a1f4e442768', 'description', 'Require formal approval before transferring personal data across borders. Approval ensures oversight and legal validation.', '2026-04-02 06:48:56.971729', '2026-04-02 06:48:56.971729'),
  ('cb7ce0f7-8502-42dc-8163-2355093302fc', '27e8116c-7cbd-4cea-a520-4a1f4e442768', 'guidance', 'Implement approval workflow for transfers.', '2026-04-02 06:48:56.971729', '2026-04-02 06:48:56.971729'),
  ('f375e522-78ec-4a20-9e24-0d680c486959', '27e8116c-7cbd-4cea-a520-4a1f4e442768', 'implementation_guidance', '["Define approval authority", "Record transfer requests", "Review compliance requirements", "Maintain approval records"]', '2026-04-02 06:48:56.971729', '2026-04-02 06:48:56.971729'),
  ('b2a56ebf-e690-48ea-b18f-eca4b0092f60', '297aa99f-f3a2-4c23-bd0d-847ab0c41fd7', 'name', 'Include Data Protection Clauses in Contracts', '2026-04-02 06:48:56.99636', '2026-04-02 06:48:56.99636'),
  ('e0e3617c-2663-4acd-86de-89cc34a4b150', '297aa99f-f3a2-4c23-bd0d-847ab0c41fd7', 'description', 'Ensure contracts with processors include obligations to protect personal data. Contractual safeguards enforce accountability.', '2026-04-02 06:48:56.99636', '2026-04-02 06:48:56.99636'),
  ('39596190-a59b-4ac2-8e9a-c325591aadc0', '297aa99f-f3a2-4c23-bd0d-847ab0c41fd7', 'guidance', 'Use standardized data protection agreements.', '2026-04-02 06:48:56.99636', '2026-04-02 06:48:56.99636'),
  ('3edae7e5-f062-46c8-b172-19b737f4a7ac', '297aa99f-f3a2-4c23-bd0d-847ab0c41fd7', 'implementation_guidance', '["Define privacy obligations", "Require breach notification clauses", "Specify security controls", "Review contracts periodically"]', '2026-04-02 06:48:56.99636', '2026-04-02 06:48:56.99636'),
  ('f4bf5a35-b4f2-4491-9b93-7f8f76cac30d', 'a74590c0-780a-4008-8a2f-5418ef0ac44e', 'name', 'Review Vendor Data Protection Agreements', '2026-04-02 06:48:57.018996', '2026-04-02 06:48:57.018996'),
  ('7dc57114-8424-40ff-95e5-1670b5cb3817', 'a74590c0-780a-4008-8a2f-5418ef0ac44e', 'description', 'Periodically review vendor contracts to ensure they remain aligned with data protection laws. Regular review prevents outdated safeguards.', '2026-04-02 06:48:57.018996', '2026-04-02 06:48:57.018996'),
  ('78ffdc09-5a3a-4a46-adc2-d6e2310a758b', 'a74590c0-780a-4008-8a2f-5418ef0ac44e', 'guidance', 'Conduct legal review of processor agreements.', '2026-04-02 06:48:57.018996', '2026-04-02 06:48:57.018996'),
  ('6fa52fb4-6356-417f-aeb9-d734e308772b', 'a74590c0-780a-4008-8a2f-5418ef0ac44e', 'implementation_guidance', '["Maintain contract inventory", "Schedule contract reviews", "Update clauses as needed", "Track review completion"]', '2026-04-02 06:48:57.018996', '2026-04-02 06:48:57.018996'),
  ('3f99d73d-e35e-4823-b7de-24f11f2935b8', 'acee0431-e9a0-4aaf-aa11-eb31c8d4333a', 'name', 'Establish Data Protection Policy', '2026-04-02 06:48:57.045452', '2026-04-02 06:48:57.045452'),
  ('bae68a70-6d26-431f-8b83-e4e850d7cf04', 'acee0431-e9a0-4aaf-aa11-eb31c8d4333a', 'description', 'Maintain a formal data protection policy defining responsibilities and requirements for handling personal data. Policies guide consistent privacy practices.', '2026-04-02 06:48:57.045452', '2026-04-02 06:48:57.045452'),
  ('90ecc258-aa9a-4bd8-a582-42d72e473cbe', 'acee0431-e9a0-4aaf-aa11-eb31c8d4333a', 'guidance', 'Align policy with legal and regulatory requirements.', '2026-04-02 06:48:57.045452', '2026-04-02 06:48:57.045452'),
  ('8b087c1f-d9e7-41f3-81a6-eab780e9868b', 'acee0431-e9a0-4aaf-aa11-eb31c8d4333a', 'implementation_guidance', '["Define privacy principles", "Assign responsibilities", "Publish policy internally", "Review annually"]', '2026-04-02 06:48:57.045452', '2026-04-02 06:48:57.045452'),
  ('eade41f7-b562-4013-9ea5-a32349d9fe15', 'c742d6b5-1fbc-4126-beea-67344364370b', 'name', 'Assign Data Protection Accountability', '2026-04-02 06:48:57.070423', '2026-04-02 06:48:57.070423'),
  ('381e1818-6f7e-42da-8a43-5d330689e09f', 'c742d6b5-1fbc-4126-beea-67344364370b', 'description', 'Assign roles responsible for overseeing compliance with data protection obligations. Accountability ensures governance effectiveness.', '2026-04-02 06:48:57.070423', '2026-04-02 06:48:57.070423'),
  ('17fa0a84-7bed-4028-8834-68e337f1bb82', 'c742d6b5-1fbc-4126-beea-67344364370b', 'guidance', 'Designate a responsible privacy or data protection officer.', '2026-04-02 06:48:57.070423', '2026-04-02 06:48:57.070423'),
  ('de66c41a-2ce2-4260-886e-8e0bcb4a5186', 'c742d6b5-1fbc-4126-beea-67344364370b', 'implementation_guidance', '["Define governance structure", "Assign privacy oversight roles", "Document responsibilities", "Report to senior management"]', '2026-04-02 06:48:57.070423', '2026-04-02 06:48:57.070423'),
  ('700feb2e-c4d6-4428-b744-4c3fdda1d2a0', 'b650a2d1-e16b-430f-b803-44ee0402f546', 'name', 'Maintain Personal Data Inventory', '2026-04-02 06:48:57.094599', '2026-04-02 06:48:57.094599'),
