  ('74d21c3d-5539-4fbb-bf73-59827be62587', 'b650a2d1-e16b-430f-b803-44ee0402f546', 'implementation_guidance', '["Identify personal data systems", "Document data flows", "Update inventory periodically", "Assign asset owners"]', '2026-04-02 06:48:57.094599', '2026-04-02 06:48:57.094599'),
  ('e6bbe9fd-297b-4ac4-84c8-a7b8a32abb0f', 'cec256c0-bfa0-4375-a6c0-0ba140b9c566', 'name', 'Classify Personal Data Assets', '2026-04-02 06:48:57.118766', '2026-04-02 06:48:57.118766'),
